import React, { useEffect, useRef, useState } from 'react'
import { useStore } from '../store'

export default function ChatWindow({ chat }) {
  const token = useStore(s => s.token)
  const focusChat = useStore(s => s.focusChat)
  const closeChat = useStore(s => s.closeChat)
  const messages = useStore(s => s.messages)
  const addMessage = useStore(s => s.addMessage)

  const messagesEndRef = useRef()
  const [text, setText] = useState('')
  const [socket, setSocket] = useState(null)

  useEffect(() => {
    // Connect to Socket.IO
    const { io } = require('socket.io-client')
    const newSocket = io('http://localhost:8000/ws', {
      query: { token }
    })

    newSocket.on('message', (msg) => {
      addMessage(msg.sender_id, msg)
    })

    setSocket(newSocket)

    return () => newSocket.close()
  }, [token])

  useEffect(() => {
    // Scroll to bottom
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages[chat.id]])

  const handleSendMessage = () => {
    if (!text.trim() || !socket) return

    socket.emit('send_message', {
      receiver_id: chat.id,
      content: text,
      content_type: 'text'
    })

    addMessage(chat.id, {
      sender_id: useStore.getState().currentUser.id,
      content: text,
      content_type: 'text'
    })

    setText('')
  }

  const chatMessages = messages[chat.id] || []

  return (
    <div
      className="fb-chat-window"
      style={{ zIndex: chat.zIndex, right: `${chat.offset || 15}px` }}
      onMouseDown={() => focusChat(chat.id)}
    >
      <div className="fb-chat-header">
        <div className="fb-chat-header-title">{chat.name}</div>
        <button
          className="fb-chat-close"
          onClick={() => closeChat(chat.id)}
          title="Close"
        >
          ×
        </button>
      </div>

      <div className="fb-chat-messages" ref={messagesEndRef}>
        {chatMessages.map((m, i) => (
          <div
            key={i}
            className={`fb-message ${m.sender_id === useStore.getState().currentUser?.id ? 'sent' : 'received'}`}
          >
            {m.content}
          </div>
        ))}
      </div>

      <div className="fb-chat-input">
        <input
          type="text"
          value={text}
          onChange={e => setText(e.target.value)}
          onKeyPress={e => e.key === 'Enter' && handleSendMessage()}
          placeholder="Aa"
        />
        <button onClick={handleSendMessage}>Send</button>
      </div>
    </div>
  )
}
